// Case 7417: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function worked_http_server_ts_responses_problems_streaming_2(status: number, problemType: string, bufferedBytes: number, highWaterMark: number): { mediaType: string; continueWriting: boolean } {
  const mediaType = status >= 400 ? "application/problem+json" : "application/json";
  if (status >= 400 && problemType.length === 0) {
    return { mediaType: "invalid-problem", continueWriting: false };
  }
  const continueWriting = bufferedBytes >= 0 && bufferedBytes < highWaterMark;
  return { mediaType, continueWriting };
}

